def validate(args, output):
    k, n = args[0], args[1]
    from itertools import combinations
    correct = set()
    for combo in combinations(range(1, 10), k):
        if sum(combo) == n:
            correct.add(combo)
    if not isinstance(output, list):
        return False
    seen = set()
    for combo in output:
        if not isinstance(combo, list) or len(combo) != k:
            return False
        for v in combo:
            if not isinstance(v, int) or v < 1 or v > 9:
                return False
        key = tuple(sorted(combo))
        if len(set(key)) != k:
            return False
        if sum(key) != n:
            return False
        if key in seen:
            return False
        seen.add(key)
    return seen == correct

