function validate(args, output) {
    const k = args[0], n = args[1];
    const correct = new Set();
    const digits = [1,2,3,4,5,6,7,8,9];
    const combo = [];
    (function bt(start) {
        if (combo.length === k) {
            if (combo.reduce((a, b) => a + b, 0) === n) correct.add(combo.join(','));
            return;
        }
        for (let i = start; i < digits.length; i++) { combo.push(digits[i]); bt(i + 1); combo.pop(); }
    })(0);
    if (!Array.isArray(output)) return false;
    const seen = new Set();
    for (const c of output) {
        if (!Array.isArray(c) || c.length !== k) return false;
        for (const v of c) { if (!Number.isInteger(v) || v < 1 || v > 9) return false; }
        const sorted = c.slice().sort((a, b) => a - b);
        if (new Set(sorted).size !== k) return false;
        if (sorted.reduce((a, b) => a + b, 0) !== n) return false;
        const key = sorted.join(',');
        if (seen.has(key)) return false;
        seen.add(key);
    }
    if (seen.size !== correct.size) return false;
    for (const key of seen) if (!correct.has(key)) return false;
    return true;
}

