class Solution:
    def combinationSum3(self, k, n):
        res = []
        path = []
        def bt(start, remaining):
            if len(path) == k:
                if remaining == 0:
                    res.append(path[:])
                return
            for d in range(start, 10):
                if d > remaining:
                    break
                path.append(d)
                bt(d + 1, remaining - d)
                path.pop()
        bt(1, n)
        res.sort()
        return res

